#!/usr/bin/env node
/**
 * Simple, production-ready web scraper for extracting entrepreneurship and finance content
 * from websites like https://carreiras.oportunidadesevagas.com.
 *
 * Features:
 * - Respects robots.txt (basic support for User-agent: * and Disallow rules, prefix matching)
 * - Polite crawling (configurable delay, custom User-Agent)
 * - Robust HTTP fetching with retries and timeout handling
 * - HTML parsing with Cheerio to extract title, description, date, and links
 * - Keyword filtering (English and Portuguese)
 * - CLI usage and JSON output
 *
 * Requirements:
 *   - Node.js 18+ (uses global fetch)
 *   - npm install cheerio
 *
 * Example:
 *   node scraper.js --start https://carreiras.oportunidadesevagas.com --maxPages 20 --delayMs 1000 --output results.json
 */

"use strict";

const fs = require("node:fs/promises");
const path = require("node:path");
const { setTimeout: sleep } = require("node:timers/promises");
const cheerio = require("cheerio");

/** Default configuration values */
const DEFAULTS = {
  maxPages: 15,          // Max pages to crawl (polite default)
  delayMs: 1500,         // Delay between requests to the same origin
  timeoutMs: 15000,      // Per-request timeout
  maxRetries: 3,         // Max retries for transient errors
  retryBaseDelayMs: 800, // Base delay for exponential backoff
  output: "results.json" // Output file
};

/** Keywords for filtering relevant content (English and Portuguese) */
const KEYWORDS = [
  // English
  "entrepreneur", "entrepreneurship", "startup", "start-up", "business",
  "venture", "founder", "founders", "finance", "financial", "finances",
  "investment", "investing", "funding", "capital", "economy", "economic",
  // Portuguese
  "empreendedor", "empreendedorismo", "startup", "negócio", "negocio",
  "empresa", "fundador", "fundadores", "finança", "finanças", "financeiro",
  "investimento", "investir", "capital", "economia", "econômico", "economico"
];

/** Precompiled regex for URL schemes to skip */
const SKIP_SCHEMES = /^(mailto:|tel:|javascript:|#)/i;

/** CLI argument parsing (simple and robust) */
function parseArgs(argv) {
  const args = { ...DEFAULTS };
  for (let i = 2; i < argv.length; i++) {
    const arg = argv[i];
    const next = argv[i + 1];
    switch (arg) {
      case "--start":
        if (!next) throw new Error("Missing value for --start");
        args.start = next;
        i++;
        break;
      case "--maxPages":
        args.maxPages = parseInt(next, 10);
        if (Number.isNaN(args.maxPages) || args.maxPages <= 0) {
          throw new Error("Invalid --maxPages value");
        }
        i++;
        break;
      case "--delayMs":
        args.delayMs = parseInt(next, 10);
        if (Number.isNaN(args.delayMs) || args.delayMs < 0) {
          throw new Error("Invalid --delayMs value");
        }
        i++;
        break;
      case "--timeoutMs":
        args.timeoutMs = parseInt(next, 10);
        if (Number.isNaN(args.timeoutMs) || args.timeoutMs <= 0) {
          throw new Error("Invalid --timeoutMs value");
        }
        i++;
        break;
      case "--output":
        if (!next) throw new Error("Missing value for --output");
        args.output = next;
        i++;
        break;
      case "--maxRetries":
        args.maxRetries = parseInt(next, 10);
        if (Number.isNaN(args.maxRetries) || args.maxRetries < 0) {
          throw new Error("Invalid --maxRetries value");
        }
        i++;
        break;
      default:
        throw new Error(`Unknown argument: ${arg}`);
    }
  }
  if (!args.start) {
    throw new Error("Missing required --start URL");
  }
  return args;
}

/** Normalize and validate URLs, ensuring same-origin links where required */
function toAbsoluteUrl(baseUrl, href) {
  if (!href || SKIP_SCHEMES.test(href)) return null;
  try {
    const abs = new URL(href, baseUrl).toString();
    // Strip fragment to deduplicate
    const u = new URL(abs);
    u.hash = "";
    return u.toString();
  } catch {
    return null;
  }
}

/** Minimal robots.txt parser for User-agent: * with Disallow prefix rules */
async function fetchRobotsRules(origin) {
  const robotsUrl = new URL("/robots.txt", origin).toString();
  try {
    const res = await fetchWithRetry(robotsUrl, { timeoutMs: 8000, maxRetries: 1 }, true);
    if (!res.ok) {
      return { disallows: [], fetched: false };
    }
    const text = await res.text();
    return parseRobotsTxt(text);
  } catch {
    return { disallows: [], fetched: false };
  }
}

/** Parse robots.txt content for User-agent: * Disallow rules (prefix matching) */
function parseRobotsTxt(content) {
  const lines = content.split(/\r?\n/);
  let isStarSection = false;
  const disallows = [];
  for (const rawLine of lines) {
    const line = rawLine.trim();
    if (!line || line.startsWith("#")) continue;
    const [keyRaw, ...rest] = line.split(":");
    if (!keyRaw || rest.length === 0) continue;
    const key = keyRaw.trim().toLowerCase();
    const value = rest.join(":").trim();
    if (key === "user-agent") {
      isStarSection = value === "*" ? true : false;
    } else if (key === "disallow" && isStarSection) {
      // Normalize path (Disallow can be empty meaning allow all)
      if (value) {
        disallows.push(value);
      }
    } else if (key === "allow" && isStarSection) {
      // We implement simple prefix disallow; "Allow" not fully supported here
      // Keeping a minimal approach—sites typically specify clear Disallow paths.
      continue;
    }
  }
  return { disallows, fetched: true };
}

/** Check if a path is allowed by robots.txt rules (simple prefix-based matching) */
function isPathAllowed(robots, urlStr) {
  try {
    const url = new URL(urlStr);
    const path = url.pathname || "/";
    for (const rule of robots.disallows) {
      // Simple prefix match; does not support wildcards
      if (rule === "/") return false;
      if (path.startsWith(rule)) return false;
    }
    return true;
  } catch {
    return false;
  }
}

/** Fetch with retries, timeout, and optional raw Response return */
async function fetchWithRetry(url, options = {}, returnResponse = false) {
  const {
    timeoutMs = DEFAULTS.timeoutMs,
    maxRetries = DEFAULTS.maxRetries,
    retryBaseDelayMs = DEFAULTS.retryBaseDelayMs
  } = options;

  let attempt = 0;
  let lastErr = null;

  while (attempt <= maxRetries) {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), timeoutMs);
    try {
      const res = await fetch(url, {
        method: "GET",
        redirect: "follow",
        signal: controller.signal,
        headers: {
          // Identify clearly and politely
          "User-Agent": "EntrepreneurshipFinanceScraper/1.0 (+https://example.com/contact)",
          "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
          "Accept-Language": "pt-BR,pt;q=0.9,en-US;q=0.8,en;q=0.7",
          "Cache-Control": "no-cache"
        }
      });
      clearTimeout(timeout);

      // Rate-limit and backoff behavior for 429/503
      if (res.status === 429 || res.status === 503) {
        const ra = parseRetryAfter(res.headers.get("retry-after"));
        const delay = ra ?? backoffDelay(retryBaseDelayMs, attempt);
        if (attempt < maxRetries) {
          await sleep(delay);
          attempt++;
          continue;
        }
      }

      // Non-2xx still return Response for caller to decide
      if (returnResponse) {
        return res;
      }

      if (!res.ok) {
        throw new Error(`HTTP ${res.status} ${res.statusText}`);
      }
      return res;
    } catch (err) {
      clearTimeout(timeout);
      lastErr = err;
      // Abort errors and network errors may be retried
      if (attempt < maxRetries) {
        await sleep(backoffDelay(retryBaseDelayMs, attempt));
        attempt++;
        continue;
      }
      break;
    }
  }
  throw lastErr || new Error("Request failed");
}

/** Exponential backoff delay with jitter */
function backoffDelay(base, attempt) {
  const exp = base * Math.pow(2, attempt);
  const jitter = Math.random() * base;
  return Math.min(15000, exp + jitter); // cap to 15s
}

/** Parse Retry-After seconds or HTTP-date */
function parseRetryAfter(value) {
  if (!value) return null;
  const seconds = Number(value);
  if (!Number.isNaN(seconds)) return seconds * 1000;
  const date = Date.parse(value);
  if (!Number.isNaN(date)) {
    const diff = date - Date.now();
    return diff > 0 ? diff : null;
  }
  return null;
}

/** Extract absolute, same-origin links from a document */
function extractLinks(baseUrl, $) {
  const base = new URL(baseUrl);
  const out = new Set();
  $("a[href]").each((_, el) => {
    const href = $(el).attr("href");
    const abs = toAbsoluteUrl(baseUrl, href);
    if (!abs) return;
    try {
      const u = new URL(abs);
      if (u.origin !== base.origin) return; // stay within same origin
      if (!["http:", "https:"].includes(u.protocol)) return;
      out.add(u.toString());
    } catch {
      // ignore malformed URLs
    }
  });
  return Array.from(out);
}

/** Normalize string for keyword matching (lowercase + remove diacritics) */
function normalizeText(s) {
  return (s || "")
    .toString()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();
}

/** Check if text matches relevant keywords */
function matchesKeywords(text) {
  const norm = normalizeText(text);
  return KEYWORDS.some((kw) => norm.includes(normalizeText(kw)));
}

/** Extract metadata (title, description, datePublished) and content snippet */
function extractContent(url, html) {
  const $ = cheerio.load(html);

  // Title candidates
  const ogTitle = $('meta[property="og:title"]').attr("content");
  const twitterTitle = $('meta[name="twitter:title"]').attr("content");
  const h1 = $("h1").first().text().trim();
  const docTitle = $("title").first().text().trim();
  const title = [ogTitle, twitterTitle, h1, docTitle].find(Boolean) || "";

  // Description candidates
  const metaDesc = $('meta[name="description"]').attr("content")
    || $('meta[property="og:description"]').attr("content")
    || $('meta[name="twitter:description"]').attr("content");
  // Fallback: first non-empty paragraph
  let firstParagraph = "";
  $("p").each((_, el) => {
    const t = $(el).text().trim();
    if (t && t.length > 60 && !firstParagraph) {
      firstParagraph = t;
    }
  });
  const description = metaDesc || firstParagraph || "";

  // Date candidates (meta/ld+json/time)
  let publishedAt = $('meta[property="article:published_time"]').attr("content")
    || $('meta[name="pubdate"]').attr("content")
    || $('meta[name="date"]').attr("content")
    || $('time[datetime]').attr("datetime")
    || "";

  // Attempt JSON-LD parsing for datePublished
  $('script[type="application/ld+json"]').each((_, el) => {
    try {
      const json = $(el).contents().text();
      const data = JSON.parse(json);
      const items = Array.isArray(data) ? data : [data];
      for (const item of items) {
        if (typeof item === "object" && item) {
          const dp = item.datePublished || item.dateCreated || (item.article && item.article.datePublished);
          if (dp && !publishedAt) {
            publishedAt = dp;
            break;
          }
        }
      }
    } catch {
      // Ignore JSON parse errors
    }
  });

  // Extract a concise text snippet to aid keyword matching
  const snippet = buildSnippet($);

  return {
    url,
    title: title.trim(),
    description: (description || snippet).trim(),
    publishedAt: publishedAt ? new Date(publishedAt).toISOString() : null,
    snippet: snippet.trim()
  };
}

/** Build a concise snippet from content paragraphs */
function buildSnippet($) {
  const parts = [];
  $("p, article p").each((_, el) => {
    const t = $(el).text().replace(/\s+/g, " ").trim();
    if (t && t.length > 40) {
      parts.push(t);
    }
    if (parts.join(" ").length > 500) {
      return false; // break loop
    }
  });
  return parts.join(" ").slice(0, 600);
}

/** Crawl a site starting from a seed URL, collecting relevant pages */
async function crawl({ start, maxPages, delayMs, timeoutMs, maxRetries, output }) {
  const startUrl = new URL(start);
  const origin = startUrl.origin;

  // Load robots.txt
  const robots = await fetchRobotsRules(origin);

  const queue = [];
  const visited = new Set();
  const results = [];
  const enqueued = new Set();

  const enqueue = (url) => {
    if (enqueued.has(url)) return;
    enqueued.add(url);
    queue.push(url);
  };

  enqueue(startUrl.toString());

  let processed = 0;

  while (queue.length > 0 && processed < maxPages) {
    const url = queue.shift();
    if (!url || visited.has(url)) continue;
    visited.add(url);

    if (!isPathAllowed(robots, url)) {
      logInfo(`Skipping disallowed by robots.txt: ${url}`);
      continue;
    }

    let res;
    try {
      res = await fetchWithRetry(url, { timeoutMs, maxRetries });
    } catch (err) {
      logWarn(`Fetch failed (${url}): ${err?.message || err}`);
      await politeDelay(delayMs);
      continue;
    }

    const contentType = res.headers.get("content-type") || "";
    if (!contentType.includes("text/html")) {
      logInfo(`Skipping non-HTML content: ${url}`);
      await politeDelay(delayMs);
      continue;
    }

    let html = "";
    try {
      html = await res.text();
    } catch (err) {
      logWarn(`Failed to read response (${url}): ${err?.message || err}`);
      await politeDelay(delayMs);
      continue;
    }

    const { title, description, publishedAt, snippet } = extractContent(url, html);
    const combinedText = [title, description, snippet].join(" ").trim();

    if (matchesKeywords(combinedText)) {
      results.push({
        url,
        title,
        description,
        publishedAt,
        discoveredAt: new Date().toISOString()
      });
      logInfo(`Matched: ${title || url}`);
    } else {
      logInfo(`No match: ${title || url}`);
    }

    // Enqueue additional same-origin links for breadth-first crawl
    const $ = cheerio.load(html);
    const links = extractLinks(url, $);
    for (const link of links) {
      if (!visited.has(link)) enqueue(link);
    }

    processed++;
    await politeDelay(delayMs);
  }

  // Deduplicate results by URL
  const unique = dedupeBy(results, (r) => r.url);

  // Persist to disk
  await writeOutput(output, unique);

  return unique;
}

/** Helper to delay between requests (politeness) */
async function politeDelay(ms) {
  if (ms > 0) await sleep(ms);
}

/** Deduplicate an array by a key selector */
function dedupeBy(items, keySelector) {
  const map = new Map();
  for (const item of items) {
    const key = keySelector(item);
    if (!map.has(key)) map.set(key, item);
  }
  return Array.from(map.values());
}

/** Write results to JSON file (pretty formatted) */
async function writeOutput(outPath, data) {
  try {
    const dir = path.dirname(outPath);
    if (dir && dir !== ".") {
      await fs.mkdir(dir, { recursive: true });
    }
    await fs.writeFile(outPath, JSON.stringify(data, null, 2), "utf8");
    logInfo(`Saved ${data.length} items to ${outPath}`);
  } catch (err) {
    logError(`Failed to write output: ${err?.message || err}`);
  }
}

/** Simple structured logging helpers to stderr */
function logInfo(msg) {
  console.error(`[INFO] ${new Date().toISOString()} ${msg}`);
}
function logWarn(msg) {
  console.error(`[WARN] ${new Date().toISOString()} ${msg}`);
}
function logError(msg) {
  console.error(`[ERROR] ${new Date().toISOString()} ${msg}`);
}

/** Graceful shutdown on SIGINT */
function setupGracefulShutdown() {
  let stopping = false;
  process.on("SIGINT", () => {
    if (stopping) return;
    stopping = true;
    logWarn("Received SIGINT, exiting gracefully...");
    // Let the process end naturally
    setTimeout(() => process.exit(0), 100);
  });
}

/** Main entry point for CLI usage */
async function main() {
  setupGracefulShutdown();
  let args;
  try {
    args = parseArgs(process.argv);
  } catch (err) {
    console.error(`Usage: node scraper.js --start <URL> [--maxPages N] [--delayMs MS] [--timeoutMs MS] [--maxRetries N] [--output file]`);
    logError(err.message);
    process.exit(1);
  }

  try {
    const items = await crawl(args);
    // Also print compact JSON to stdout to support piping (optional)
    process.stdout.write(JSON.stringify(items) + "\n");
  } catch (err) {
    logError(`Crawl failed: ${err?.message || err}`);
    process.exit(1);
  }
}

if (require.main === module) {
  main();
}

module.exports = {
  crawl,
  extractContent,
  matchesKeywords
};

#!/usr/bin/env node
/**
 * Automated Football Match Odds Checker
 *
 * Description:
 *   This Node.js script visits https://vidhyaclinic.com, discovers outbound links,
 *   filters for likely betting/sportsbook websites, and then attempts to search for a
 *   specific football match on each site to check availability and scrape nearby odds.
 *
 *   The scraping is heuristic and best-effort. Many sportsbook sites are dynamic and
 *   may have geo-restrictions, logins, or bot protection. The script is designed to
 *   fail gracefully and report status per site.
 *
 * Usage:
 *   node odds-checker.js --match "Arsenal vs Chelsea" [--date "2025-01-01"] [--league "Premier League"] [--sites "https://examplebook.com,https://othersports.com"] [--maxSites 10] [--concurrency 3] [--timeoutMs 45000] [--out results.json]
 *
 * Dependencies:
 *   npm install playwright cheerio p-limit
 *
 * Notes:
 * - Respect each target site's Terms of Service and robots.txt before scraping.
 * - Consider rate limiting and adding a proxy if required for compliance.
 * - This script uses Playwright (Chromium) for robust page interaction.
 */

'use strict';

const fs = require('fs');
const path = require('path');
const { setTimeout: delay } = require('timers/promises');
const crypto = require('crypto');
const { URL } = require('url');

const cheerio = require('cheerio');
const pLimit = require('p-limit');
const { chromium } = require('playwright');

// --------------------------- Configuration ---------------------------

const DEFAULT_SOURCE_URL = 'https://vidhyaclinic.com';
const DEFAULT_TIMEOUT_MS = 45_000;
const DEFAULT_CONCURRENCY = 3;
const DEFAULT_MAX_SITES = 10;

const USER_AGENT =
  'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/126.0.0.0 Safari/537.36';

const BETTING_KEYWORDS = [
  'bet',
  'sports',
  'sport',
  'odds',
  'book',
  'bookmaker',
  'bookies',
  '365',
  'betway',
  'bwin',
  'unibet',
  'pinnacle',
  'williamhill',
  'ladbrokes',
  'coral',
  'betfair',
  '888',
  'marathon',
  'dafabet',
  '10bet',
  'parimatch',
  'stake',
  'betmgm',
  'draftkings',
  'fanduel',
  'pointsbet',
  'caesars',
];

// Common cookie/consent button text to auto-accept
const CONSENT_BUTTON_TEXTS = [
  'accept',
  'agree',
  'ok',
  'got it',
  'continue',
  'allow',
  'yes',
  'i consent',
];

// --------------------------- CLI Argument Parsing ---------------------------

function parseArgs(argv) {
  const args = {};
  for (let i = 2; i < argv.length; i++) {
    const arg = argv[i];
    const next = argv[i + 1];

    const setKV = (k, v) => {
      args[k] = v;
      i++;
    };

    if (arg === '--match' && next) setKV('match', next);
    else if (arg === '--date' && next) setKV('date', next);
    else if (arg === '--league' && next) setKV('league', next);
    else if (arg === '--sites' && next) setKV('sites', next);
    else if (arg === '--source' && next) setKV('source', next);
    else if (arg === '--timeoutMs' && next) setKV('timeoutMs', Number(next));
    else if (arg === '--concurrency' && next) setKV('concurrency', Number(next));
    else if (arg === '--maxSites' && next) setKV('maxSites', Number(next));
    else if (arg === '--out' && next) setKV('out', next);
    else if (arg === '--headful') args.headful = true;
    else if (arg === '--help' || arg === '-h') args.help = true;
  }
  return args;
}

function printHelp() {
  console.log(`
Usage:
  node odds-checker.js --match "Arsenal vs Chelsea" [options]

Options:
  --match        Required. Match query string (e.g., "Arsenal vs Chelsea").
  --date         Optional. Date string to refine search (e.g., "2025-01-01").
  --league       Optional. League string to refine search (e.g., "Premier League").
  --sites        Optional. Comma-separated list of site URLs to check (bypasses discovery).
  --source       Optional. Source page to discover sites (default: ${DEFAULT_SOURCE_URL}).
  --maxSites     Optional. Limit on number of discovered sites to process (default: ${DEFAULT_MAX_SITES}).
  --concurrency  Optional. Number of concurrent site checks (default: ${DEFAULT_CONCURRENCY}).
  --timeoutMs    Optional. Per-site timeout in milliseconds (default: ${DEFAULT_TIMEOUT_MS}).
  --out          Optional. Output JSON file path (default: results-<timestamp>.json).
  --headful      Optional. Run browser in non-headless mode for debugging.
  --help, -h     Show this help.
`);
}

// --------------------------- Utility Helpers ---------------------------

function nowIso() {
  return new Date().toISOString();
}

function hashString(s) {
  return crypto.createHash('sha256').update(s).digest('hex').slice(0, 8);
}

function toAbsoluteUrl(base, href) {
  try {
    return new URL(href, base).toString();
  } catch {
    return null;
  }
}

function isLikelyBettingHost(hostname) {
  const lower = hostname.toLowerCase();
  return BETTING_KEYWORDS.some((kw) => lower.includes(kw));
}

function uniqueBy(array, keyFn) {
  const seen = new Set();
  const out = [];
  for (const item of array) {
    const key = keyFn(item);
    if (!seen.has(key)) {
      seen.add(key);
      out.push(item);
    }
  }
  return out;
}

function sanitizeText(s) {
  return s.replace(/\s+/g, ' ').trim();
}

function normalizeQuery(match, date, league) {
  const parts = [match, date, league].filter(Boolean).map((s) => s.trim());
  return sanitizeText(parts.join(' '));
}

function within(val, min, max) {
  return val >= min && val <= max;
}

function tryParseOdds(tokens) {
  // Returns an array of { format, value } objects from an array of tokens or a string.
  const text = Array.isArray(tokens) ? tokens.join(' ') : String(tokens);
  const found = [];

  // Decimal odds: 1.01 to 100 (capture up to two decimals)
  const decimalRegex = /\b([1-9]\d?(\.\d{1,3})?)\b/g;

  // Fractional odds: d+/d+ (e.g., 10/3, 7/2)
  const fractionalRegex = /\b(\d{1,3}\/\d{1,3})\b/g;

  // American odds: +150, -200 (avoid matching phone numbers by context)
  const americanRegex = /(?<!\d)([+-]\d{2,4})(?!\d)/g;

  let m;
  while ((m = decimalRegex.exec(text)) !== null) {
    const v = parseFloat(m[1]);
    if (within(v, 1.01, 100)) {
      found.push({ format: 'decimal', value: m[1] });
    }
  }
  while ((m = fractionalRegex.exec(text)) !== null) {
    found.push({ format: 'fraction', value: m[1] });
  }
  while ((m = americanRegex.exec(text)) !== null) {
    const num = parseInt(m[1], 10);
    if (within(Math.abs(num), 100, 10000)) {
      found.push({ format: 'american', value: m[1] });
    }
  }

  // Deduplicate by value-format combo
  return uniqueBy(found, (o) => `${o.format}:${o.value}`);
}

function buildOutputPath(filepath) {
  if (filepath) return path.resolve(process.cwd(), filepath);
  const fname = `results-${new Date().toISOString().replace(/[:.]/g, '-')}.json`;
  return path.resolve(process.cwd(), fname);
}

function shortHost(u) {
  try {
    return new URL(u).hostname;
  } catch {
    return u;
  }
}

// --------------------------- Network Fetch ---------------------------

async function fetchHtml(url, timeoutMs = 15000) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const res = await fetch(url, {
      signal: controller.signal,
      headers: {
        'User-Agent': USER_AGENT,
        'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
      },
    });
    if (!res.ok) {
      throw new Error(`HTTP ${res.status}`);
    }
    return await res.text();
  } finally {
    clearTimeout(timeout);
  }
}

async function discoverBettingSitesFromSource(sourceUrl, maxSites) {
  const html = await fetchHtml(sourceUrl, 15000);
  const $ = cheerio.load(html);

  const hrefs = [];
  $('a[href]').each((_, el) => {
    const href = $(el).attr('href');
    const abs = toAbsoluteUrl(sourceUrl, href);
    if (!abs) return;
    try {
      const u = new URL(abs);
      // Skip same origin
      if (u.origin === new URL(sourceUrl).origin) return;
      // Skip non-http(s)
      if (u.protocol !== 'http:' && u.protocol !== 'https:') return;
      hrefs.push(u);
    } catch {
      // ignore bad URLs
    }
  });

  const filtered = hrefs
    .filter((u) => isLikelyBettingHost(u.hostname))
    .map((u) => u.toString());

  const deduped = uniqueBy(filtered, (u) => new URL(u).hostname);
  // Hard limit
  return deduped.slice(0, maxSites);
}

// --------------------------- Playwright Helpers ---------------------------

async function newBrowser(headful = false) {
  return chromium.launch({
    headless: !headful,
    args: [
      '--no-sandbox',
      '--disable-blink-features=AutomationControlled',
      '--disable-dev-shm-usage',
    ],
  });
}

async function newContext(browser) {
  return browser.newContext({
    userAgent: USER_AGENT,
    viewport: { width: 1366, height: 900 },
    locale: 'en-US',
    timezoneId: 'UTC',
  });
}

async function acceptConsentIfPresent(page) {
  try {
    // Quick scan for common consent buttons
    const buttons = await page.$$('button, input[type=button], input[type=submit]');
    for (const btn of buttons) {
      const txt = ((await btn.textContent()) || '').toLowerCase().trim();
      const val = ((await btn.getAttribute('value')) || '').toLowerCase().trim();
      if (
        CONSENT_BUTTON_TEXTS.some((w) => txt.includes(w)) ||
        CONSENT_BUTTON_TEXTS.some((w) => val.includes(w))
      ) {
        await btn.click({ timeout: 500 }).catch(() => {});
      }
    }
    // Also check links
    const links = await page.$$('a');
    for (const a of links) {
      const txt = ((await a.textContent()) || '').toLowerCase().trim();
      if (CONSENT_BUTTON_TEXTS.some((w) => txt.includes(w))) {
        await a.click({ timeout: 500 }).catch(() => {});
      }
    }
  } catch {
    // ignore errors
  }
}

async function findAndUseSearch(page, query) {
  const selectors = [
    'input[type="search"]',
    'input[placeholder*="Search" i]',
    'input[placeholder*="Find" i]',
    'input[aria-label*="Search" i]',
    'input[name*="search" i]',
    'input[name*="q" i]',
    'input[type="text"]',
  ];

  for (const sel of selectors) {
    const el = await page.$(sel);
    if (el) {
      // Ensure visibility and not disabled
      const disabled = await el.isDisabled().catch(() => true);
      if (disabled) continue;
      await el.click({ timeout: 1000 }).catch(() => {});
      await el.fill('', { timeout: 1000 }).catch(() => {});
      await el.type(query, { delay: 50 }).catch(() => {});
      await Promise.race([
        el.press('Enter').catch(() => {}),
        (async () => {
          // Some sites need a search button click
          const btn = await page.$('button[type="submit"], button[aria-label*="search" i], button:has-text("Search")');
          if (btn) await btn.click().catch(() => {});
        })(),
      ]);
      // Wait for some page change or network activity
      await Promise.race([
        page.waitForLoadState('networkidle', { timeout: 5000 }),
        page.waitForTimeout(2000),
      ]);
      return true;
    }
  }
  return false;
}

async function pageTextContent(page) {
  // Extract large text content for scanning; avoid full HTML to reduce noise
  const bodyHandle = await page.$('body');
  if (!bodyHandle) return '';
  const text = await bodyHandle.innerText().catch(() => '');
  return sanitizeText(text || '');
}

function buildMatchRegex(query) {
  // Try to be flexible: if query is "Arsenal vs Chelsea", split on vs
  const q = query.toLowerCase();
  const parts = q.split(/\bvs\b|\bv\s*\.\s*\b|-/i).map((s) => sanitizeText(s.toLowerCase()));
  const escaped = parts.map((p) => p.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).filter(Boolean);
  if (escaped.length >= 2) {
    // Look for both team names within up to ~100 characters
    return new RegExp(`(${escaped[0]})([\\s\\S]{0,100})(${escaped[1]})`, 'i');
  }
  // Fallback: search for entire query loosely
  const loose = query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  return new RegExp(loose, 'i');
}

function extractNearbyOddsFromText(text, matchRegex) {
  // Find a window around the match occurrence and parse odds within that window
  const m = text.match(matchRegex);
  if (!m || m.index == null) return { odds: [], snippet: '' };
  const idx = m.index;
  const windowSize = 800;
  const start = Math.max(0, idx - Math.floor(windowSize / 2));
  const end = Math.min(text.length, idx + windowSize);
  const snippet = text.slice(start, end);
  const odds = tryParseOdds(snippet);
  return { odds, snippet: sanitizeText(snippet).slice(0, 1000) };
}

async function evaluateSite(page, siteUrl, query, timeoutMs) {
  // Load the page with a timeout
  const response = await page.goto(siteUrl, { waitUntil: 'domcontentloaded', timeout: Math.min(15000, timeoutMs) });
  if (!response) {
    return { availability: 'error', error: 'No response' };
  }
  const status = response.status();
  if (status >= 400) {
    return { availability: 'error', error: `HTTP ${status}` };
  }

  await acceptConsentIfPresent(page);

  const matchRegex = buildMatchRegex(query);

  // Try using search
  await findAndUseSearch(page, query).catch(() => {});

  // Attempt to scroll to load dynamic content
  for (let i = 0; i < 3; i++) {
    await page.mouse.wheel(0, 800);
    await page.waitForTimeout(600);
  }

  // Check text content
  const text = await pageTextContent(page);
  const blockedSignals = [/not available in your region/i, /access denied/i, /forbidden/i, /verify you are human/i, /are you a robot/i, /restricted/i, /geolocation/i];
  if (blockedSignals.some((r) => r.test(text))) {
    return { availability: 'blocked' };
  }

  const hasMatch = matchRegex.test(text);
  if (!hasMatch) {
    // Try a different approach: Look for team tokens individually
    const tokens = query.split(/\s+vs\s+|\s+v\s+\.?\s+|-/i).map((s) => s.trim()).filter(Boolean);
    const tokenPresence = tokens.map((t) => new RegExp(t.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'i').test(text));
    if (tokenPresence.filter(Boolean).length < 2) {
      return { availability: 'not_found' };
    }
  }

  const { odds, snippet } = extractNearbyOddsFromText(text, matchRegex);
  return {
    availability: 'available',
    odds,
    snippet,
  };
}

// --------------------------- Main Flow ---------------------------

async function run() {
  const args = parseArgs(process.argv);
  if (args.help) {
    printHelp();
    process.exit(0);
  }

  const match = args.match;
  if (!match || !match.trim()) {
    console.error('Error: --match is required. Example: --match "Arsenal vs Chelsea"');
    process.exit(1);
  }

  const date = args.date;
  const league = args.league;
  const source = args.source || DEFAULT_SOURCE_URL;
  const timeoutMs = Number.isFinite(args.timeoutMs) ? args.timeoutMs : DEFAULT_TIMEOUT_MS;
  const concurrency = Number.isFinite(args.concurrency) ? args.concurrency : DEFAULT_CONCURRENCY;
  const maxSites = Number.isFinite(args.maxSites) ? args.maxSites : DEFAULT_MAX_SITES;
  const headful = !!args.headful;
  const outPath = buildOutputPath(args.out);

  const query = normalizeQuery(match, date, league);

  // Resolve sites
  let sites = [];
  if (args.sites) {
    sites = args.sites
      .split(',')
      .map((s) => s.trim())
      .filter(Boolean)
      .map((s) => (s.startsWith('http') ? s : `https://${s}`));
  } else {
    try {
      sites = await discoverBettingSitesFromSource(source, maxSites);
      if (sites.length === 0) {
        console.warn(`[${nowIso()}] No likely betting sites discovered from ${source}.`);
      }
    } catch (err) {
      console.error(`[${nowIso()}] Failed to discover sites from ${source}: ${err && err.message ? err.message : String(err)}`);
    }
  }

  if (sites.length === 0) {
    console.error('No target sites to check. Provide --sites or ensure source has outbound sportsbook links.');
    process.exit(2);
  }

  console.log(`[${nowIso()}] Checking ${sites.length} site(s) for match: "${query}"`);

  const browser = await newBrowser(headful);
  const limit = pLimit(Math.max(1, concurrency));

  const results = [];
  try {
    const tasks = sites.map((siteUrl) =>
      limit(async () => {
        const ctx = await newContext(browser);
        const page = await ctx.newPage();
        // Per-site timer
        const siteTimer = setTimeout(() => {
          try {
            page.close().catch(() => {});
            ctx.close().catch(() => {});
          } catch {}
        }, timeoutMs);

        const label = shortHost(siteUrl);
        const started = Date.now();
        let result = {
          site: label,
          url: siteUrl,
          startedAt: nowIso(),
          status: 'unknown',
          availability: 'unknown',
          odds: [],
          snippet: '',
          error: undefined,
          durationMs: undefined,
          id: `${label}-${hashString(siteUrl)}`,
        };

        try {
          const evaluation = await evaluateSite(page, siteUrl, query, timeoutMs);
          result.availability = evaluation.availability;
          result.odds = evaluation.odds || [];
          result.snippet = evaluation.snippet || '';
          result.status = 'ok';
        } catch (err) {
          result.status = 'error';
          result.error = err && err.message ? err.message : String(err);
          if ((result.error || '').toLowerCase().includes('timeout')) {
            result.availability = 'timeout';
          } else {
            result.availability = 'error';
          }
        } finally {
          result.durationMs = Date.now() - started;
          clearTimeout(siteTimer);
          await page.close().catch(() => {});
          await ctx.close().catch(() => {});
        }

        console.log(
          `[${nowIso()}] ${label}: ${result.availability}` +
            (result.odds && result.odds.length ? `, odds found: ${result.odds.map((o) => o.value).slice(0, 5).join(', ')}` : '')
        );

        results.push(result);
      })
    );

    await Promise.allSettled(tasks);
  } finally {
    await browser.close().catch(() => {});
  }

  // Persist results
  const payload = {
    query: {
      match,
      date: date || null,
      league: league || null,
      normalized: query,
    },
    source: args.sites ? 'provided' : source,
    checkedAt: nowIso(),
    results,
  };

  try {
    fs.writeFileSync(outPath, JSON.stringify(payload, null, 2), 'utf-8');
    console.log(`[${nowIso()}] Results saved to ${outPath}`);
  } catch (err) {
    console.error(`[${nowIso()}] Failed to write results: ${err && err.message ? err.message : String(err)}`);
    process.exit(3);
  }
}

// --------------------------- Entry Point ---------------------------

if (require.main === module) {
  run().catch((err) => {
    console.error(`[${nowIso()}] Fatal error: ${err && err.stack ? err.stack : String(err)}`);
    process.exit(1);
  });
}

/**
 * verifyUrlContainsKeywords
 * -------------------------
 * Fetches a URL (with timeout and size limits) and checks whether the URL string
 * or the retrieved page content contains one or more given keywords.
 *
 * - Works in modern browsers and Node.js 18+ (which provide the Fetch API).
 * - Includes robust error handling, timeouts, response size limits, and basic content-type checks.
 * - Case-insensitive substring matching by default; optional whole-word matching.
 *
 * Example:
 *  const result = await verifyUrlContainsKeywords(
 *    'https://sk-delta.vercel.app',
 *    ['Juu17 Brands', 'Another Keyword'],
 *    { timeoutMs: 12000, maxBytes: 1_500_000, matchWholeWord: false }
 *  );
 *  console.log(result);
 *
 * Returned object structure:
 * {
 *   url: string,                     // original URL requested
 *   finalUrl: string | null,         // final URL after redirects (if any)
 *   status: number | null,           // HTTP status code or null if not reached
 *   statusText: string | null,       // HTTP status text or null if not reached
 *   contentType: string | null,      // response Content-Type (if available)
 *   foundInUrl: string[],            // keywords found within the URL string
 *   foundInContent: string[],        // keywords found within the response text
 *   missingKeywords: string[],       // keywords not found in either place
 *   foundAny: boolean,               // at least one keyword found
 *   foundAll: boolean,               // all keywords found
 *   tookMs: number,                  // total elapsed time in ms
 *   error: null | {                  // present if a network/processing error occurred
 *     code?: string,
 *     message: string
 *   }
 * }
 */
async function verifyUrlContainsKeywords(url, keywords, options = {}) {
  const startedAt = Date.now();

  // Validate environment
  if (typeof fetch !== 'function') {
    throw new Error('Fetch API is not available in this environment.');
  }

  // Validate URL
  if (typeof url !== 'string' || url.trim() === '') {
    throw new TypeError('Parameter "url" must be a non-empty string.');
  }
  const normalizedUrl = url.trim();

  // Normalize keywords to an array of non-empty strings
  const kwArray = Array.isArray(keywords) ? keywords : [keywords];
  const cleanedKeywords = kwArray
    .map((k) => (typeof k === 'string' ? k.trim() : ''))
    .filter((k) => k.length > 0);

  if (cleanedKeywords.length === 0) {
    throw new TypeError('Parameter "keywords" must include at least one non-empty string.');
  }

  // Options with defaults
  const {
    timeoutMs = 15000,         // request timeout in milliseconds
    maxBytes = 1_000_000,      // maximum allowed response size in bytes
    requireHtml = false,       // if true, only analyze responses that look like HTML
    matchWholeWord = false,    // if true, enforce whole-word matching
    userAgent,                 // user-agent string (Node.js only; browsers ignore)
    acceptLanguages = 'en-US,en;q=0.9'
  } = options;

  // Helpers
  const toLower = (s) => s.toLocaleLowerCase('en');
  const lcKeywords = cleanedKeywords.map(toLower);

  // Pre-check: look for keywords in the URL string itself (case-insensitive)
  const foundInUrl = [];
  const urlLower = toLower(normalizedUrl);
  for (let i = 0; i < lcKeywords.length; i++) {
    if (simpleMatch(urlLower, lcKeywords[i], { wholeWord: matchWholeWord })) {
      foundInUrl.push(cleanedKeywords[i]);
    }
  }

  // Prepare fetch with timeout via AbortController
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), Math.max(1, timeoutMs));

  // Prepare headers (avoid setting forbidden headers in browsers)
  const headers = new Headers({
    Accept: 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
    'Accept-Language': acceptLanguages
  });

  // Attempt to set user-agent in Node.js (will be ignored/forbidden in browsers)
  if (userAgent && isNodeLike() && typeof userAgent === 'string') {
    headers.set('User-Agent', userAgent);
  }

  let response = null;
  let contentType = null;
  let textContent = '';
  let finalUrl = null;
  let status = null;
  let statusText = null;
  let fetchError = null;

  try {
    response = await fetch(normalizedUrl, {
      method: 'GET',
      headers,
      redirect: 'follow',
      signal: controller.signal,
      // mode is left default; in browsers, cross-origin requests may be restricted by CORS
    });

    finalUrl = typeof response.url === 'string' ? response.url : normalizedUrl;
    status = response.status;
    statusText = response.statusText || null;

    // If the response is "opaque" (browser no-cors), we can't read the body
    if (response.type === 'opaque') {
      throw makeError('OPAQUE_RESPONSE', 'Opaque response (CORS/no-cors), cannot read content.');
    }

    // Content-Type check
    contentType = getContentType(response.headers.get('content-type'));

    // Optionally require HTML-like content before proceeding
    if (requireHtml && !looksLikeHtml(contentType)) {
      throw makeError(
        'UNSUPPORTED_CONTENT_TYPE',
        `Content-Type "${contentType || 'unknown'}" is not HTML-like and requireHtml is true.`
      );
    }

    // Enforce maxBytes via Content-Length (if provided)
    const contentLengthHeader = response.headers.get('content-length');
    if (contentLengthHeader) {
      const contentLength = parseInt(contentLengthHeader, 10);
      if (!Number.isNaN(contentLength) && contentLength > maxBytes) {
        throw makeError(
          'RESPONSE_TOO_LARGE',
          `Response size (${contentLength} bytes) exceeds the limit (${maxBytes} bytes).`
        );
      }
    }

    // Read response text with streaming and size limit
    textContent = await readResponseTextWithLimit(response, maxBytes);
  } catch (err) {
    fetchError = normalizeError(err);
  } finally {
    clearTimeout(timeoutId);
  }

  // Analyze content if available
  const foundInContent = [];
  if (textContent && typeof textContent === 'string') {
    const textLower = toLower(textContent);
    for (let i = 0; i < lcKeywords.length; i++) {
      if (simpleMatch(textLower, lcKeywords[i], { wholeWord: matchWholeWord })) {
        foundInContent.push(cleanedKeywords[i]);
      }
    }
  }

  // Collate results
  const uniqueFound = uniqueStrings([...foundInUrl, ...foundInContent]);
  const missingKeywords = cleanedKeywords.filter((k) => !uniqueFound.includes(k));
  const result = {
    url: normalizedUrl,
    finalUrl: finalUrl,
    status: status,
    statusText: statusText,
    contentType: contentType,
    foundInUrl,
    foundInContent,
    missingKeywords,
    foundAny: uniqueFound.length > 0,
    foundAll: missingKeywords.length === 0,
    tookMs: Date.now() - startedAt,
    error: fetchError
  };

  return result;
}

/**
 * Simple case-insensitive matching that optionally enforces whole-word matches.
 * Expects haystack/needle already lower-cased.
 */
function simpleMatch(haystackLower, needleLower, { wholeWord = false } = {}) {
  if (!wholeWord) {
    return haystackLower.includes(needleLower);
  }

  // Whole word matching using word boundaries. Escape needle for regex safely.
  const escaped = needleLower.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  // Use unicode-aware boundaries where supported. Fallback to basic boundaries otherwise.
  let pattern;
  try {
    pattern = new RegExp(`\\b${escaped}\\b`, 'ui'); // unicode + case-insensitive (even though we lowercased)
  } catch {
    pattern = new RegExp(`\\b${escaped}\\b`, 'i');
  }
  return pattern.test(haystackLower);
}

/**
 * Streams a response body into a string with a strict byte limit to prevent
 * excessive memory usage. Uses TextDecoder to properly handle multi-byte sequences.
 */
async function readResponseTextWithLimit(response, maxBytes) {
  if (!response || !response.body) {
    // Some environments or certain responses may not have a body (e.g., HEAD requests).
    return '';
  }

  const reader = response.body.getReader();
  const decoder = new TextDecoder(); // default utf-8; fetch typically decodes content-encoding automatically
  let received = 0;
  let result = '';

  try {
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      // Enforce byte limit
      received += value.byteLength;
      if (received > maxBytes) {
        // Cancel the reader to free resources
        try { reader.cancel(); } catch (_) { /* noop */ }
        throw makeError(
          'RESPONSE_TOO_LARGE',
          `Response stream exceeded the limit of ${maxBytes} bytes.`
        );
      }

      // Stream-decoding to string
      result += decoder.decode(value, { stream: true });
    }

    // Flush any remaining decoder buffer
    result += decoder.decode();
    return result;
  } finally {
    try { reader.releaseLock(); } catch (_) { /* noop */ }
  }
}

/**
 * Extracts the MIME type (without parameters) from a Content-Type header value.
 */
function getContentType(contentTypeHeader) {
  if (!contentTypeHeader || typeof contentTypeHeader !== 'string') return null;
  const [type] = contentTypeHeader.split(';').map((s) => s.trim().toLowerCase());
  return type || null;
}

/**
 * Determines if the content type suggests HTML content.
 */
function looksLikeHtml(contentType) {
  if (!contentType) return false;
  return (
    contentType === 'text/html' ||
    contentType === 'application/xhtml+xml'
  );
}

/**
 * Create a standardized error object.
 */
function makeError(code, message) {
  const err = new Error(message);
  if (code) err.code = code;
  return err;
}

/**
 * Converts unknown errors into a normalized, serializable shape.
 */
function normalizeError(err) {
  if (!err) return null;

  // AbortError shape unification
  const isAbort =
    err.name === 'AbortError' ||
    err.code === 'ABORT_ERR' ||
    (typeof DOMException !== 'undefined' && err instanceof DOMException && err.name === 'AbortError');

  return {
    code: isAbort ? 'ABORTED' : (err.code || err.name || 'ERROR'),
    message: String(err.message || err.toString() || 'Unknown error')
  };
}

/**
 * Deduplicate case-sensitive strings while preserving order.
 */
function uniqueStrings(arr) {
  const seen = new Set();
  const out = [];
  for (const s of arr) {
    if (!seen.has(s)) {
      seen.add(s);
      out.push(s);
    }
  }
  return out;
}

/**
 * Rudimentary detection if running in Node-like environment.
 */
function isNodeLike() {
  return (
    typeof process !== 'undefined' &&
    process.versions != null &&
    process.versions.node != null
  );
}

// Optional: expose as CommonJS module (Node) and global (browser)
try {
  if (typeof module !== 'undefined' && module.exports) {
    module.exports = { verifyUrlContainsKeywords };
  }
} catch (_) { /* noop */ }

try {
  if (typeof window !== 'undefined') {
    window.verifyUrlContainsKeywords = verifyUrlContainsKeywords;
  } else if (typeof globalThis !== 'undefined') {
    globalThis.verifyUrlContainsKeywords = verifyUrlContainsKeywords;
  }
} catch (_) { /* noop */ }
